package com.hospital.management.util;import java.util.*;/** Documents permitted derived bill-state transitions. */public final class BillStatusTransition{private static final Map<String,Set<String>>R=Map.of("UNPAID",Set.of("UNPAID","PARTIALLY_PAID","PAID","CANCELLED"),"PARTIALLY_PAID",Set.of("UNPAID","PARTIALLY_PAID","PAID","REFUNDED"),"PAID",Set.of("UNPAID","PARTIALLY_PAID","REFUNDED"),"CANCELLED",Set.of("CANCELLED"),"REFUNDED",Set.of("REFUNDED"));private BillStatusTransition(){}public static boolean isAllowed(String from,String to){return R.getOrDefault(from,Set.of()).contains(to);}}
